Here's a modern MSTest test class for `DataFetcher`:

```csharp
using System.Net;
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public class DataFetcherTests
{
    // Modern MSTest natively supports async Task test methods
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    // Use [Timeout] in milliseconds to fail slow tests
    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new MockHttpMessageHandler("data", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("data", result);
    }

    // Test that cancellation is respected
    [TestMethod]
    public async Task FetchAsync_ThrowsWhenCancelled()
    {
        var handler = new MockHttpMessageHandler("data", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(5));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Test non-success status codes
    [TestMethod]
    public async Task FetchAsync_ThrowsOnNonSuccessStatusCode()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // Minimal testable handler — no external mocking library needed
    private class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode, TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            cancellationToken.ThrowIfCancellationRequested();

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---------|-----|
| Async tests | Return `async Task` — MSTest awaits them natively |
| Timeouts | `[Timeout(ms)]` attribute fails the test if it exceeds the duration |
| Cancellation | Pass a pre-cancelled `CancellationTokenSource` and assert `TaskCanceledException` |
| No external deps | Subclass `HttpMessageHandler` instead of mocking `HttpClient` directly |

Avoid `async void` test methods — MSTest can't observe their exceptions. Always use `async Task`.
